const email = $('When Lead Submitted').first().json.body.email || '';
const domain = email.includes('@') ? email.split('@')[1].toLowerCase().trim() : '';
return { domain };

const newsResp = $input.item.json;
let newsText = 'No third-party intelligence found';
try {
  const blocks = (newsResp.content || []).filter(b => b.type === 'text');
  if (blocks.length > 0) newsText = blocks[blocks.length - 1].text || 'No results';
} catch(e) { newsText = 'News search error: ' + String(e); }

const websiteResp = $('Get Company Website').first().json;
let rawHtml = '';
if (websiteResp.body && typeof websiteResp.body === 'string') rawHtml = websiteResp.body;
else if (websiteResp.data && typeof websiteResp.data === 'string') rawHtml = websiteResp.data;
else if (typeof websiteResp === 'string') rawHtml = websiteResp;

const websiteText = rawHtml
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<link[^>]*>/gi, ' ')
  .replace(/<[^>]{1,500}>/g, ' ')
  .replace(/https?:\/\/\S+/g, ' ')
  .replace(/\s+/g, ' ')
  .replace(/[^\x20-\x7E]/g, '')
  .trim()
  .substring(0, 1200) || 'Website not accessible';

const body   = $('When Lead Submitted').first().json.body;
const config = $('Set Lead Scoring Params').first().json;
const domain = $('Extract Domain from Email').first().json.domain;

const leadName     = body.name       || '';
const leadEmail    = body.email      || '';
const leadCompany  = body.company    || '';
const leadJobTitle = body.job_title  || '';
const leadMessage  = body.message    || '';
const myIcp        = config.my_icp;

const prompt = 'You are a B2B sales qualification expert. Score this inbound lead against the ICP.\n\n'
  + 'ICP:\n' + myIcp + '\n\n'
  + 'Lead Information:\n'
  + '- Name: '      + leadName      + '\n'
  + '- Email: '     + leadEmail     + '\n'
  + '- Company: '   + leadCompany   + '\n'
  + '- Job Title: ' + leadJobTitle  + '\n'
  + '- Message: '   + (leadMessage || '(no message provided)') + '\n\n'
  + 'Company Website (stripped homepage text):\n'
  + websiteText + '\n\n'
  + 'Third-Party Intelligence (news, funding, press from external sources):\n'
  + newsText + '\n\n'
  + 'SCORING RULES — follow these strictly:\n'
  + '1. Treat the form message as LOW-RELIABILITY self-reported data. Anyone can write anything.\n'
  + '2. Score 7-10 (hot/SQL) ONLY if at least 2 of these independent signals are present:\n'
  + '   - Seniority confirmed by job title (VP, Head of, Director, C-suite, Founder)\n'
  + '   - Corporate domain (not gmail/hotmail/yahoo/outlook personal email)\n'
  + '   - Website confirms company type and approximate size\n'
  + '   - Third-party intelligence found (funding, press, reviews, analyst mentions)\n'
  + '3. If message claims budget/urgency but NO corroborating signals exist, cap score at 5.\n'
  + '4. Empty or vague message is fine — rely on the other signals instead.\n'
  + '5. A gmail/personal email address with no company website = maximum score 3.\n'
  + '6. State WHICH signals drove the score in the reason field — be specific.\n\n'
  + 'Return ONLY valid JSON (no markdown, no code blocks):\n'
  + '{"score":<1-10>,"tier":"hot|warm|cold","reason":"<one sentence listing the specific signals that determined this score>","email_subject":"<subject line>","email_body":"<3-4 sentence professional reply>"}';

const requestBody = {
  model: 'claude-opus-4-5',
  max_tokens: 512,
  temperature: 0.2,
  messages: [{ role: 'user', content: prompt }]
};

return {
  domain,
  website_text:        websiteText,
  news_research:       newsText,
  lead_name:           leadName,
  lead_email:          leadEmail,
  lead_company:        leadCompany,
  lead_job_title:      leadJobTitle,
  lead_message:        leadMessage,
  my_icp:              myIcp,
  hot_threshold:       config.hot_threshold,
  warm_threshold:      config.warm_threshold,
  sales_slack_channel: config.sales_slack_channel,
  requestBody
};

const text    = $input.item.json.content[0].text;
const ai      = JSON.parse(text);
const config  = $('Set Lead Scoring Params').first().json;
const profile = $('Compile Lead Profile').first().json;
const score   = ai.score;
const tier    = score >= config.hot_threshold ? 'hot' : score >= config.warm_threshold ? 'warm' : 'cold';

return {
  ai_score:            score,
  ai_tier:             tier,
  ai_reason:           ai.reason,
  ai_email_subject:    ai.email_subject,
  ai_email_body:       ai.email_body,
  lead_name:           profile.lead_name,
  lead_email:          profile.lead_email,
  lead_company:        profile.lead_company,
  lead_job_title:      profile.lead_job_title,
  sales_slack_channel: profile.sales_slack_channel
};
